import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import Input from '../../components/Inputs/Input'

const Login = ({setcurrentPage}) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState(null);

  const navigate = useNavigate();

  //Handle Login Form submit
  const handleLogin = async (e) => {
    e.preventDefault();
  };

  return (
    <div className="w-[90vw] md:w-[33vw] p-7 flex flex-col justify-center">
      <h3 className="text-lg font-semibold text-black"> Welcome Back  </h3>
      <p className="text-xs text-slate-700 mt-[5px] mb-6"> Please enter your detials to continue </p>
      <form onSubmit={handleLogin}>
        <Input 
        label="Email Address"
        type="email"
        value={email}
        onChange={({target}) => setEmail(target.value)}
        placeholder="john@example.com"
        />
        <Input 
        label="Password"
        type="password"
        value={password}
        onChange={({target}) => setPassword(target.value)}
        placeholder="********"
        />
        {error && <p className="text-red-500 text-xs mb-4">{error}</p>}
        <button type="submit" className="w-full bg-primary text-white py-2 rounded-md hover:bg-primary/90 transition-colors">
          Login
        </button>
        <p className="text-xs text-slate-700 mt-4">
          Don't have an account? <span className="text-primary cursor-pointer" onClick={() => setcurrentPage("signup")}>Sign Up</span>
        </p>
      </form>
    </div>
  )
}

export default Login

import React, { useState } from "react";

import HERO_IMG from "../assets/hero-img.png";
import { APP_FEATURES } from "../utils/data";
import { useNavigate } from "react-router-dom";
import Modal from "../components/Modal";
import Login from "./Auth/Login";
import Signup from "./Auth/SignUp";
const LandingPage = () => {
  const navigate = useNavigate();

  const [openAuthmodal, setopenAuthModal] = useState(false);
  const [currentPage, setcurrentPage] = useState("login");

  const handleCTA = () => {};
  return (
   <>
   <div className="w-full min-h-screen bg-[#FFFCEF] font-sans relative pb-20">
      {/* Glow Effect matching original */}
      <div className="w-[500px] h-[500px] bg-amber-200/30 blur-[65px] absolute top-0 left-0 pointer-events-none"></div>

      <div className="max-w-7xl mx-auto px-6 lg:px-12 relative z-10">
        {/* Header */}
