          <button 
            className="px-6 py-2.5 rounded-full text-sm font-medium text-white bg-[#F39845] hover:bg-[#e28835] transition-colors" 
            onClick={() => setopenAuthModal(true)}
          >
            Login / Sign Up
          </button>
        </header>

        {/* Hero Section */}
        <div className="flex flex-col lg:flex-row items-center justify-between mt-12 gap-10">
          <div className="flex-1">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-[#F39845]/50 bg-[#F39845]/10 mb-6">
              {/* Sparkles Icon */}
              <svg className="w-3.5 h-3.5 text-[#F39845]" fill="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path d="M11.642 1.054a.75.75 0 01.716 0l1.921 3.52 3.868.514a.75.75 0 01.403 1.29l-2.83 2.658.749 3.824a.75.75 0 01-1.103.823L12 11.666l-3.366 1.817a.75.75 0 01-1.103-.823l.749-3.824-2.83-2.658a.75.75 0 01.403-1.29l3.868-.514 1.921-3.52z" />
              </svg>
              <span className="text-xs font-medium text-[#F39845] tracking-wide">AI Powered</span>
            </div>

            <h1 className="text-5xl lg:text-[3.5rem] xl:text-[4rem] font-medium text-slate-900 leading-tight">
              Ace Interviews with <br />
              <span className="text-[#F39845] font-semibold">AI-Powered</span> Learning
            </h1>
          </div>

          <div className="flex-1 lg:max-w-md lg:ml-10">
            <p className="text-base text-slate-700 mb-8 leading-relaxed font-light">
              Get role-specific questions, expand answers when you need them,
              dive deeper into concepts, and organize everything your way. From
              preparation to mastery ΓÇö your ultimate interview toolkit is here.
            </p>
            <button 
              className="px-8 py-3.5 rounded-full text-white font-medium text-sm bg-black hover:bg-slate-800 transition-colors" 
              onClick={handleCTA}
            >
              Get Started
            </button>
          </div>
        </div>

        {/* Hero Image Section */}
        <div className="mt-16 w-full flex justify-center">
            {/* Using padding-top or styling block if HERO_IMG is full browser window screenshot */}
            <div className="w-full max-w-5xl rounded-[1rem] lg:rounded-[1.5rem] overflow-hidden">
                {/* Fallback pattern hidden by default, shown via onError below */}
                <img 
                    src={HERO_IMG} 
                    alt="App Interface Mockup" 
                    className="w-full h-auto object-cover border border-[#eddfc7] rounded-[1rem] lg:rounded-[1.5rem]" 
                    onError={(e) => {
                      e.target.style.display = 'none';
                      e.target.nextSibling.style.display = 'flex';
                    }}
                />
                <div className="hidden w-full h-[500px] flex-col items-center justify-center bg-gray-100 rounded-[1.5rem] border border-gray-200">
                    <span className="text-gray-400 font-medium">Platform Mockup Missing</span>
                </div>
            </div>
        </div>

        {/* Features Section */}
        <div className="mt-28 mb-16 px-2 lg:px-4">
          <h2 className="text-[1.5rem] lg:text-[1.8rem] font-normal text-center text-slate-900 mb-10">
            Features That Make You Shine
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {APP_FEATURES.slice(0, 3).map((feature) => (
              <div key={feature.id} className="bg-white rounded-[1.2rem] p-8 border border-[#eddfc7]">
                <h3 className="text-lg font-medium text-slate-900 mb-4">{feature.title}</h3>
                <p className="text-[0.95rem] text-slate-600 leading-relaxed font-light">{feature.description}</p>
              </div>
            ))}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
            {APP_FEATURES.slice(3, 5).map((feature) => (
              <div key={feature.id} className="bg-white rounded-[1.2rem] p-8 border border-[#eddfc7]">
                <h3 className="text-lg font-medium text-slate-900 mb-4">{feature.title}</h3>
                <p className="text-[0.95rem] text-slate-600 leading-relaxed font-light">{feature.description}</p>
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
    <Modal 
       isOpen={openAuthmodal}
       onClose={() => {
        setopenAuthModal(false);
        setcurrentPage("login");
       } }
       hideHeader
       >
        <div>
          {currentPage === "login" && (
            <Login setcurrentPage={setcurrentPage} />
          )}
          {currentPage === "signup" && (
            <Signup setcurrentPage={setcurrentPage} />
          )}
        </div>
       </Modal>
    </>
  );
};

export default LandingPage;
